function isSyntaxCharacter(c) {
  switch (c) {
    case "^":
    case "$":
    case "\\":
    case ".":
    case "*":
    case "+":
    case "?":
    case "(":
    case ")":
    case "[":
    case "]":
    case "{":
    case "}":
    case "|":
      return true;
    default:
      return false;
  }
}

function isAlphaDigit(c) {
  return ("0" <= c && c <= "9") || ("A" <= c && c <= "Z") || ("a" <= c && c <= "z");
}


// IdentityEscape in AtomEscape.
//
// AtomEscape[U] :: CharacterEscape[?U]
// CharacterEscape[U] :: IdentityEscape[?U]
